class t{constructor(){this.accordions=document.querySelectorAll(".faq-accordion"),0!==this.accordions.length&&this.init()}init(){this.accordions.forEach(t=>{this.initAccordion(t)})}initAccordion(t){const e=t.querySelectorAll(".faq-item");e&&0!==e.length&&e.forEach(t=>{const e=t.querySelector(".faq-question"),i=t.querySelector(".faq-answer");e&&i&&e.addEventListener("click",()=>{t.classList.contains("is-active")?(t.classList.remove("is-active"),e.setAttribute("aria-expanded","false")):(t.classList.add("is-active"),e.setAttribute("aria-expanded","true"))})})}}new t;export{t as default};
